#include <cuda_runtime.h>

__global__ void hotspotOpt1_kernel(const float *p, const float *tIn, float *tOut, float sdc,
                                   int nx, int ny, int nz,
                                   float ce, float cw,
                                   float cn, float cs,
                                   float ct, float cb,
                                   float cc)
{
    const float amb_temp = 80.0f;

    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= nx || j >= ny) return;

    int c = i + j * nx;
    int xy = nx * ny;

    int W = (i == 0)    ? c : c - 1;
    int E = (i == nx-1) ? c : c + 1;
    int N = (j == 0)    ? c : c - nx;
    int S = (j == ny-1) ? c : c + nx;

    float temp1, temp2, temp3;
    temp1 = temp2 = tIn[c];
    temp3 = tIn[c + xy];
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;

    c += xy;
    W += xy;
    E += xy;
    N += xy;
    S += xy;

    for (int k = 1; k < nz - 1; ++k) {
        temp1 = temp2;
        temp2 = temp3;
        temp3 = tIn[c + xy];
        tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
        c += xy;
        W += xy;
        E += xy;
        N += xy;
        S += xy;
    }

    temp1 = temp2;
    temp2 = temp3;
    tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
}

extern "C" cudaError_t hotspotOpt1_launch(const float *p, const float *tIn, float *tOut, float sdc,
                                          int nx, int ny, int nz,
                                          float ce, float cw,
                                          float cn, float cs,
                                          float ct, float cb,
                                          float cc,
                                          cudaStream_t stream)
{
    dim3 block(64, 4);
    dim3 grid((unsigned int)((nx + block.x - 1) / block.x),
              (unsigned int)((ny + block.y - 1) / block.y));

    hotspotOpt1_kernel<<<grid, block, 0, stream>>>(p, tIn, tOut, sdc,
                                                   nx, ny, nz,
                                                   ce, cw, cn, cs, ct, cb, cc);
    return cudaGetLastError();
}

